import React, { useState, useEffect, useCallback } from 'react';
import { 
  Container, AppBar, Toolbar, Typography, Button, Box, Tabs, Tab, 
  Card, CardContent, Badge, Chip, Grid, FormControl, InputLabel, 
  Select, MenuItem, TablePagination, TextField, Stack, Paper,
  Table, TableBody, TableCell, TableContainer, TableHead, TableRow
} from '@mui/material';
import { 
  Notifications, School, SupervisorAccount, CheckCircle, 
  RadioButtonUnchecked, Assignment, EventNote, Work, Campaign
} from '@mui/icons-material';
import axios from 'axios';

const API_BASE = 'http://4.224.186.213/evaluation-service/notifications';
const PRIORITY_MAP = { Placement: 3, Result: 2, Event: 1 };

const SAMPLE_NOTIFICATIONS = [
  { ID: 'VTU10001', Type: 'Placement', Message: 'Campus placement drive - Company XYZ on 2026-06-22 at 10:00 AM. Register by 2026-06-20.', Timestamp: '2026-06-15 09:12:00', weight: 3, Target: 'Students', Author: 'Career Cell' },
  { ID: 'VTU10002', Type: 'Result', Message: 'Semester results declared for CSE - Check portal for details.', Timestamp: '2026-06-14 14:20:00', weight: 2, Target: 'All', Author: 'Exams Office' },
  { ID: 'VTU10003', Type: 'Event', Message: 'Annual sports meet registration open. Venue: Main ground.', Timestamp: '2026-06-12 08:30:00', weight: 1, Target: 'All', Author: 'Sports Club' },
  { ID: 'VTU10004', Type: 'Placement', Message: 'Internship opportunity: Apply to ABC Labs by sending resume.', Timestamp: '2026-06-10 11:00:00', weight: 3, Target: 'Students', Author: 'Training Office' },
  { ID: 'VTU10005', Type: 'Event', Message: 'Guest lecture on AI on 2026-06-18 in Auditorium.', Timestamp: '2026-06-09 16:00:00', weight: 1, Target: 'All', Author: 'Computer Science Dept' }
];

const logMiddleware = (action, metadata) => {
  const timestamp = new Date().toISOString();
  console.log(`[LOG MIDDLEWARE] [${timestamp}] ACTION: ${action} | DATA:`, JSON.stringify(metadata));
};

export default function App() {
  const [role, setRole] = useState('student'); 
  const [currentTab, setCurrentTab] = useState(0); 
  const [notifications, setNotifications] = useState([]);
  const [viewedIds, setViewedIds] = useState(new Set());
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [messageInput, setMessageInput] = useState('');
  const [typeInput, setTypeInput] = useState('Event');
  const [audienceInput, setAudienceInput] = useState('All');

  const fetchSystemNotifications = useCallback(async () => {
    try {
      const typeParam = categoryFilter !== 'All' ? `&notification_type=${categoryFilter}` : '';
      const requestUrl = `${API_BASE}?page=${page + 1}&limit=${rowsPerPage}${typeParam}`;
      
      logMiddleware('API_FETCH_INITIATED', { requestUrl, page, rowsPerPage, categoryFilter });
      
      const res = await axios.get(requestUrl);
      const incomingData = res.data.notifications || [];

      const normalizedData = incomingData.map((item, index) => {
        const id = (typeof item.ID === 'string' && item.ID.startsWith('VTU'))
          ? item.ID
          : `VTU${20000 + (index * 13) + Math.floor(Math.random() * 4000)}`;

        return {
          ...item,
          ID: id,
          weight: PRIORITY_MAP[item.Type] || 0,
          dateObject: new Date(item.Timestamp),
          Timestamp: item.Timestamp || new Date().toISOString().replace('T', ' ').substring(0, 19),
          Target: item.Target || 'All',
          Author: item.Author || 'System'
        };
      });

      if (currentTab === 1) {
        normalizedData.sort((a, b) => b.weight - a.weight || b.dateObject - a.dateObject);
      } else {
        normalizedData.sort((a, b) => b.dateObject - a.dateObject);
      }

      setNotifications(normalizedData.length ? normalizedData : SAMPLE_NOTIFICATIONS);
      logMiddleware('API_FETCH_SUCCESS', { count: normalizedData.length });
    } catch (err) {
      logMiddleware('API_FETCH_FAILURE', { error: err.message });
      // Fall back to sample dataset so UI shows meaningful content
      setNotifications(SAMPLE_NOTIFICATIONS);
    }
  }, [page, rowsPerPage, categoryFilter, currentTab]);

  useEffect(() => {
    fetchSystemNotifications();
  }, [fetchSystemNotifications]);

  const markAsReadOrUnread = (notificationId) => {
    setViewedIds(prev => {
      const updated = new Set(prev);
      if (updated.has(notificationId)) {
        updated.delete(notificationId);
      } else {
        updated.add(notificationId);
      }
      logMiddleware('STATUS_TOGGLED', { id: notificationId, viewed: updated.has(notificationId) });
      return updated;
    });
  };

  const facultyBroadcast = (e) => {
    e.preventDefault();
    if (!messageInput.trim()) return;

    const customBroadcast = {
      ID: `VTU${Math.floor(10000 + Math.random() * 90000)}`,
      Type: typeInput,
      Message: messageInput,
      Timestamp: new Date().toISOString().replace('T', ' ').substring(0, 19),
      weight: PRIORITY_MAP[typeInput],
      dateObject: new Date()
    };

    setNotifications(prev => [customBroadcast, ...prev]);
    logMiddleware('FACULTY_BROADCAST_PUBLISHED', customBroadcast);
    setMessageInput('');
  };

  const renderCategoryStyles = (type) => {
    switch (type) {
      case 'Placement': return { color: '#0288d1', icon: <Work /> };
      case 'Result': return { color: '#9c27b0', icon: <Assignment /> };
      default: return { color: '#2e7d32', icon: <EventNote /> };
    }
  };

  // derive the notifications to show depending on the current tab
  const displayedNotifications = React.useMemo(() => {
    const base = notifications.length ? notifications : SAMPLE_NOTIFICATIONS;

    // apply category filter
    const filtered = base.filter(n => categoryFilter === 'All' ? true : n.Type === categoryFilter);

    if (currentTab === 1) {
      // Priority Inbox: show items with higher weight first and only medium/high priority
      return filtered
        .filter(n => (n.weight || 0) >= 2)
        .slice()
        .sort((a, b) => (b.weight || 0) - (a.weight || 0) || new Date(b.Timestamp) - new Date(a.Timestamp));
    }

    // Live Inbox: most recent first
    return filtered.slice().sort((a, b) => new Date(b.Timestamp) - new Date(a.Timestamp));
  }, [notifications, currentTab, categoryFilter]);

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f4f6f9' }}>
      <AppBar position="sticky" sx={{ background: 'linear-gradient(90deg, #0f172a 0%, #1e293b 100%)', boxShadow: 4 }}>
        <Toolbar sx={{ justifyContent: 'space-between' }}>
            <Stack direction="row" alignItems="center" spacing={1.5}>
            <Notifications sx={{ fontSize: 28, color: '#38bdf8' }} />
            <Typography variant="h6" sx={{ fontWeight: 700, letterSpacing: 0.5 }}>
              Campus Alerts Dashboard
            </Typography>
          </Stack>
          <Stack direction="row" spacing={2}>
            <Button 
              variant={role === 'student' ? 'contained' : 'text'}
              onClick={() => setRole('student')}
              startIcon={<School />}
              sx={{ color: role === 'student' ? '#fff' : '#94a3b8', bgcolor: role === 'student' ? '#0288d1' : 'transparent', '&:hover': { bgcolor: role === 'student' ? '#01579b' : 'rgba(255,255,255,0.08)' }, borderRadius: 2, px: 3 }}
            >
              Student Portal
            </Button>
            <Button 
              variant={role === 'faculty' ? 'contained' : 'text'}
              onClick={() => setRole('faculty')}
              startIcon={<SupervisorAccount />}
              sx={{ color: role === 'faculty' ? '#fff' : '#94a3b8', bgcolor: role === 'faculty' ? '#ed6c02' : 'transparent', '&:hover': { bgcolor: role === 'faculty' ? '#b55302' : 'rgba(255,255,255,0.08)' }, borderRadius: 2, px: 3 }}
            >
              Faculty Panel
            </Button>
          </Stack>
        </Toolbar>
      </AppBar>

      <Container maxWidth="lg" sx={{ mt: 5, pb: 6 }}>
        <Box sx={{ mb: 4 }}>
          <Typography variant="h4" sx={{ fontWeight: 800, color: '#1e293b', mb: 1 }}>
            {role === 'student' ? 'Welcome Back, Student' : 'Faculty Admin Center'}
          </Typography>
          <Typography variant="body2" color="textSecondary">
            {role === 'student' ? 'Track real-time placement status, campus updates, and evaluation scores.' : 'Publish live dynamic system alerts across campus sub-networks.'}
          </Typography>
        </Box>

        {role === 'faculty' && (
          <Paper elevation={0} sx={{ p: 3, mb: 4, borderRadius: 3, border: '1px solid #e2e8f0', bgcolor: '#ffffff' }}>
            <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 3 }}>
              <Campaign color="warning" />
              <Typography variant="h6" sx={{ fontWeight: 700, color: '#334155' }}>
                Create Live System Notice
              </Typography>
            </Stack>
            <Box component="form" onSubmit={facultyBroadcast}>
              <Grid container spacing={2.5} alignItems="center">
                <Grid item xs={12} sm={3}>
                  <FormControl fullWidth>
                    <InputLabel>Target Category</InputLabel>
                    <Select 
                      value={typeInput} 
                      label="Target Category" 
                      onChange={(e) => setTypeInput(e.target.value)}
                    >
                      <MenuItem value="Placement">Placement Notice</MenuItem>
                      <MenuItem value="Result">Result Announcement</MenuItem>
                      <MenuItem value="Event">Campus Event</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12} sm={7}>
                  <TextField 
                    fullWidth 
                    label="Compose announcement details..." 
                    value={messageInput} 
                    onChange={(e) => setMessageInput(e.target.value)} 
                  />
                </Grid>
                <Grid item xs={12} sm={2}>
                  <Button fullWidth type="submit" variant="contained" color="warning" sx={{ height: 56, borderRadius: 2, fontWeight: 600 }}>
                    Broadcast
                  </Button>
                </Grid>
              </Grid>
            </Box>
          </Paper>
        )}

        <Stack direction={{ xs: 'column', sm: 'row' }} justifyContent="space-between" alignItems={{ xs: 'flex-start', sm: 'center' }} spacing={2} sx={{ borderBottom: '2px solid #e2e8f0', mb: 3 }}>
          <Tabs value={currentTab} onChange={(e, val) => { setCurrentTab(val); setPage(0); }} sx={{ '& .MuiTab-root': { fontWeight: 700, fontSize: '0.95rem' } }}>
            <Tab label="Live Inbox Feed" />
            <Tab label="🔥 Priority Inbox" />
          </Tabs>

          <Box sx={{ pb: 1, minWidth: 200 }}>
            <FormControl fullWidth size="small">
              <InputLabel>Type Filter</InputLabel>
              <Select 
                value={categoryFilter} 
                label="Type Filter" 
                onChange={(e) => { setCategoryFilter(e.target.value); setPage(0); }}
              >
                <MenuItem value="All">All Categories</MenuItem>
                <MenuItem value="Placement">Placements</MenuItem>
                <MenuItem value="Result">Results</MenuItem>
                <MenuItem value="Event">Events</MenuItem>
              </Select>
            </FormControl>
          </Box>
        </Stack>

        <TableContainer component={Paper} sx={{ mb: 2, borderRadius: 3 }}>
          <Table>
            <TableHead sx={{ bgcolor: '#0f172a', '& th': { color: '#fff', fontWeight: 700 } }}>
              <TableRow>
                <TableCell>ID</TableCell>
                <TableCell>Type</TableCell>
                <TableCell>Message</TableCell>
                <TableCell>Timestamp</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Priority</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {displayedNotifications
                .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
                .map((item) => {
                  const hasBeenViewed = viewedIds.has(item.ID);
                  const priorityLabel = item.weight === 3 ? 'High' : item.weight === 2 ? 'Medium' : 'Low';
                  return (
                    <TableRow key={item.ID} hover onClick={() => markAsReadOrUnread(item.ID)} sx={{ cursor: 'pointer' }}>
                      <TableCell>{item.ID}</TableCell>
                      <TableCell>{item.Type}</TableCell>
                      <TableCell sx={{ maxWidth: 600, whiteSpace: 'normal' }}>{item.Message}</TableCell>
                      <TableCell>{item.Timestamp}</TableCell>
                      <TableCell>{hasBeenViewed ? 'Viewed' : 'Unread'}</TableCell>
                      <TableCell>{priorityLabel}</TableCell>
                    </TableRow>
                  );
                })}
            </TableBody>
          </Table>
        </TableContainer>

        <TablePagination
          component="div"
          count={displayedNotifications.length}
          page={page}
          onPageChange={(e, newPage) => setPage(newPage)}
          rowsPerPage={rowsPerPage}
          onRowsPerPageChange={(e) => { setRowsPerPage(parseInt(e.target.value, 10)); setPage(0); }}
          rowsPerPageOptions={[5, 10, 20]}
          sx={{ mt: 3 }}
        />
      </Container>
    </Box>
  );
}
